B.ag2=new A.am("Silver Power",B.Xw)
B.Xg=s(["Each shift, a member of dishroom (usually the unloader) should restock the custodial closet, bringing up chemicals and other necessary supplies from the basement.","If there are no back-ups in the basement, inform your supervisor or lead trainer."],t.s)
B.agA=new A.am("Restocking",B.Xg)
