B.aeT=new A.cy("Medical Emergencies I",u.E,null,B.o,B.R1)
B.Tc=s(["The pulpers turn waste into pulp, which is then used to fertilize BYU Campus.","Do not reach into the pulper unless you have turned off the Disconnect Switch."],t.s)
B.agR=new A.am("Safety",B.Tc)
B.TN=s(["Banana peels","Watermelon rinds","Pineapple tops","Excessive rice and quinoa","Eggshells","Bones","Grease/oils","Wooden sticks","Styrofoam","Metal","Plastic","Paper dishes","Wrappers"],t.s)
B.agB=new A.am("These Items Cannot Go in the Pulper",B.TN)
B.Ry=s(["Make sure the pulper is filled and turned on, with the lid closed.","Check whether the Emergency Stop is engaged.","If not running, drain, refill, insert cardboard and run again.",'If the "Overflow" light is flashing, spray out the back chute of the Mother pulper. Ensure that the sensors of the Mother pulper are clear and that the laser is properly aligned.'],t.s)
B.afR=new A.am("If the Pulper Isn't Working",B.Ry)
B.QX=s(["Each shift a cardboard box should be broken down and run through the dishroom and scullery pulpers.","Sunday Dinner Dishroom cleans the pulpers at the end of the day."],t.s)
B.agq=new A.am("Reminders",B.QX)
B.T4=s([B.agR,B.agB,B.afR,B.agq],t.J)
B.aeU=new A.cy("Pulpers","Ensure employees know how to maintain and properly use the pulper.","Take the crew to dishroom or scullery to show them the pulper.",B.o,B.T4)
B.X1=s(["P-day Clothes: Never let missionaries in P-day clothes into the main cafeteria. Send them to the sack room or to change.","Receipts: Always ask employees and senior missionaries if they would like a receipt.","Closing duties: refill napkins, restock salt/pepper, refill hand sanitizer, take lost and found to front desk, write next meal menu (including hot/fresh bar item), and spot sweep tile floor.","Erasing boards: use a napkin and hand sanitizer, NEVER a rag."],t.s)
B.ago=new A.am("Main Cashier",B.X1)
B.SL=s(["Complete assigned secondary job.","Keep black pans (cambros) filled for utensils and condiments."],t.s)
